const ethRaw = Number({{@oracle-eth:Read ETH Price.result.unnamedOutput1}});
const ethPrice = ethRaw / 1e18;
const oracleAge = Number({{@oracle-eth:Read ETH Price.result.unnamedOutput2}});
const now = Math.floor(Date.now() / 1000);
const staleMinutes = Math.floor((now - oracleAge) / 60);
const wstethRate = Number({{@lido-rate:Get wstETH Rate.result}}) / 1e18;
const supplyRatePerSec = Number({{@compound-rate:Get USDC Supply Rate.result}});
const supplyAPR = supplyRatePerSec > 0 ? ((supplyRatePerSec / 1e18) * 31536000 * 100).toFixed(2) : "0.00";
const ethFmt = new Intl.NumberFormat("en-US", {style:"currency",currency:"USD"}).format(ethPrice);
return {
  ethPrice: ethFmt,
  ethRaw: ethPrice.toFixed(2),
  staleMinutes: String(staleMinutes),
  wstethRate: wstethRate.toFixed(4),
  compoundAPR: supplyAPR,
  summary: `ETH: ${ethFmt} (${staleMinutes}m old) | wstETH: ${wstethRate.toFixed(4)} stETH | Compound USDC APR: ${supplyAPR}%`
};

